args.sparql:
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (SUBSTR(STR(?eventDate), 1, 4) AS ?year)
WHERE {
  ?event wdt:P31 wd:Q192772;
         wdt:P177 wd:Q172578;
         wdt:P1322 ?hostCity;
         wdt:P585 ?eventDate.
  ?hostCity wdt:P17 wd:Q30.
}
ORDER BY DESC(?eventDate)
LIMIT 1
